SELECT * FROM user_info
WHERE username = #{username}
  AND deleted = 0

    AND tenant_id = #{tenantId}

SELECT * FROM user_info
WHERE phone = #{phone}
  AND deleted = 0

    AND tenant_id = #{tenantId}

SELECT u.* FROM user_info u LEFT JOIN tenant_config tc ON u.tenant_id = tc.tenant_id AND tc.deleted = 0 WHERE u.deleted = 0
AND u.tenant_id = #{tenantId}
AND ( u.username LIKE CONCAT('%', #{keyword}, '%') OR u.email LIKE CONCAT('%', #{keyword}, '%') OR tc.company_name LIKE CONCAT('%', #{keyword}, '%') ) ORDER BY u.created_time DESC
